class Solution {
public:
    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        int minStableFactor = n;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int hcf = findHighestCommonFactor(nums[i], nums[j]);
                if (hcf <= maxC) {
                    minStableFactor = min(minStableFactor, nums[i] + nums[j]);
                }
            }
        }
        return minStableFactor;
    }

private:
    int findHighestCommonFactor(int num1, int num2) {
        int hcf = num1;
        while (num2 > hcf) {
            hcf = findHighestCommonFactor(hcf, num2);
        }
        return hcf;
    }
};
